    /// Creates an inspection result for a DLL with no F4SE exports.
    pub const fn non_f4se() -> Self {
        Self {
            exports_load: false,
            exports_preload: false,
            exports_query: false,
            exports_version: false,
            supports_ng: None,
            supports_ae: None,
            version_data_warning: None,
        }
