                diagnostics.skipped_entry_count += 1;
                diagnostics.record(
                    F4seScanDiagnosticKind::SkippedEntry,
                    Some(entry.path),
                    "Entry is not a direct DLL file and was skipped.",
                );
                continue;
            }

            let dll_name = display_file_name(&entry.path);
            if dll_name.starts_with("msdia") {
                diagnostics.skipped_entry_count += 1;
                diagnostics.record(
                    F4seScanDiagnosticKind::SkippedEntry,
