            Ok(bytes) => bytes,
            Err(error) => {
                diagnostics.unreadable_dll_count += 1;
                diagnostics.record_platform_error(
                    F4seScanDiagnosticKind::FileReadFailed,
                    Some(path.to_path_buf()),
