                    Some(path.to_path_buf()),
                    error.safe_message(),
                );
                warn!(
                    event = "f4se-scan-dll-inspection-failed",
                    dll_name,
                    path = %path.display(),
                    error = %error,
                    "F4SE candidate DLL failed PE/export inspection safely"
